import{_ as l,o as t,c as i,a2 as e}from"./chunks/framework.CsRSSXt_.js";const c=JSON.parse('{"title":"目录","description":"","frontmatter":{"title":"目录","order":0,"part":"导览"},"headers":[],"relativePath":"chapters/outline.md","filePath":"chapters/outline.md","lastUpdated":1781406891000}'),o={name:"chapters/outline.md"};function r(u,a,n,h,q,s){return t(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="《从0到1理解ai》—-章节大纲" tabindex="-1">《从0到1理解AI》— 章节大纲 <a class="header-anchor" href="#《从0到1理解ai》—-章节大纲" aria-label="Permalink to &quot;《从0到1理解AI》— 章节大纲&quot;">​</a></h1><blockquote><p>全书 14 章的清单与结构。</p></blockquote><hr><h2 id="part-0-·-导览-钩子" tabindex="-1">Part 0 · 导览（钩子） <a class="header-anchor" href="#part-0-·-导览-钩子" aria-label="Permalink to &quot;Part 0 · 导览（钩子）&quot;">​</a></h2><h3 id="第-0-章-全景导览-先跑一个-agent" tabindex="-1">第 0 章　全景导览 + 先跑一个 agent <a class="header-anchor" href="#第-0-章-全景导览-先跑一个-agent" aria-label="Permalink to &quot;第 0 章　全景导览 + 先跑一个 agent&quot;">​</a></h3><ul><li>AI 这条线怎么走到今天：规则 → 机器学习 → 深度学习 → 大模型 → agent</li><li>先跑一个能调工具的小 agent（API + 几十行 TypeScript），让你先看到终点长什么样</li><li>全书地图：三大段如何串成一根线</li><li>第一性原理宣言：这本书的核心信念</li></ul><hr><h2 id="part-a-·-原理骨-广度-够用-但骨头-1-在此讲透" tabindex="-1">Part A · 原理骨（广度&quot;够用&quot;，但骨头 #1 在此讲透） <a class="header-anchor" href="#part-a-·-原理骨-广度-够用-但骨头-1-在此讲透" aria-label="Permalink to &quot;Part A · 原理骨（广度&quot;够用&quot;，但骨头 #1 在此讲透）&quot;">​</a></h2><h3 id="第-1-章-机器到底怎么-学-—-🔒-第一性原理-1-学习-参数更新" tabindex="-1">第 1 章　机器到底怎么&quot;学&quot; — 🔒 第一性原理 #1：学习 = 参数更新 <a class="header-anchor" href="#第-1-章-机器到底怎么-学-—-🔒-第一性原理-1-学习-参数更新" aria-label="Permalink to &quot;第 1 章　机器到底怎么&quot;学&quot; — 🔒 第一性原理 #1：学习 = 参数更新&quot;">​</a></h3><ul><li>什么是&quot;学习&quot;：从经验里调参数，让误差变小</li><li>损失：怎么衡量&quot;错得多离谱&quot;</li><li>梯度下降：沿着下坡方向走</li><li>反向传播：错误怎么一步步追责到每个参数（直觉，不堆公式）</li><li>▶ 动手：一维线性回归演示——看参数自己滑到对的位置</li></ul><h3 id="第-2-章-神经网络-—-把简单的东西拼成强大的" tabindex="-1">第 2 章　神经网络 — 把简单的东西拼成强大的 <a class="header-anchor" href="#第-2-章-神经网络-—-把简单的东西拼成强大的" aria-label="Permalink to &quot;第 2 章　神经网络 — 把简单的东西拼成强大的&quot;">​</a></h3><ul><li>神经元 = 线性组合 + 非线性激活（为什么必须有激活：没它再多层也只是线性）</li><li>从一层到深度：深度为什么管用（特征的层次组合）</li><li>过拟合 / 泛化：模型为什么会&quot;死记硬背&quot;，怎么治</li><li>▶ 动手：两层网络分类演示</li></ul><h3 id="第-3-章-监督学习-—-给答案-学规律" tabindex="-1">第 3 章　监督学习 — 给答案，学规律 <a class="header-anchor" href="#第-3-章-监督学习-—-给答案-学规律" aria-label="Permalink to &quot;第 3 章　监督学习 — 给答案，学规律&quot;">​</a></h3><ul><li>监督学习 = 给 (输入, 标签)，学一个映射</li><li>分类 vs 回归；它的瓶颈：要大量标注</li><li>伏笔：监督学习是 RLHF 的一条腿，后面会接回来</li></ul><h3 id="第-4-章-强化学习-—-给奖励-学策略" tabindex="-1">第 4 章　强化学习 — 给奖励，学策略 <a class="header-anchor" href="#第-4-章-强化学习-—-给奖励-学策略" aria-label="Permalink to &quot;第 4 章　强化学习 — 给奖励，学策略&quot;">​</a></h3><ul><li>监督 vs 强化：给答案 vs 给分数</li><li>核心词汇：智能体 / 环境 / 状态 / 动作 / 奖励 / 回报</li><li>探索 vs 利用；策略梯度（最简直觉：让&quot;导致好结果的动作&quot;以后更可能出现）</li><li>▶ 动手：网格世界演示——看 agent 自己学会走路</li><li>伏笔：这正是 RLHF 和&quot;agent 自我进化&quot;的内核</li></ul><hr><h2 id="part-b-·-llm-核心-骨头-2-在此讲透-并和-1-接上" tabindex="-1">Part B · LLM 核心（骨头 #2 在此讲透，并和 #1 接上） <a class="header-anchor" href="#part-b-·-llm-核心-骨头-2-在此讲透-并和-1-接上" aria-label="Permalink to &quot;Part B · LLM 核心（骨头 #2 在此讲透，并和 #1 接上）&quot;">​</a></h2><h3 id="第-5-章-大模型到底是什么-—-🔒-第一性原理-2-大模型-下一个-token-的概率函数" tabindex="-1">第 5 章　大模型到底是什么 — 🔒 第一性原理 #2：大模型 = &quot;下一个 token 的概率函数&quot; <a class="header-anchor" href="#第-5-章-大模型到底是什么-—-🔒-第一性原理-2-大模型-下一个-token-的概率函数" aria-label="Permalink to &quot;第 5 章　大模型到底是什么 — 🔒 第一性原理 #2：大模型 = &quot;下一个 token 的概率函数&quot;&quot;">​</a></h3><ul><li>一句话定义：LLM 是函数 <code>f(上下文) → 下一个 token 的概率分布</code></li><li>token 是什么（分词）；这个函数有多大、它&quot;记住&quot;了什么（不是数据库，是压缩的世界知识）</li><li>从概率函数出发，所有现象都能解释：生成=采样、温度、幻觉、重复、上下文</li><li>▶ 动手：调 API 拿 logits，演示 temperature / top-k 采样</li></ul><h3 id="第-6-章-transformer-—-让-读懂上下文-变强的架构" tabindex="-1">第 6 章　Transformer — 让&quot;读懂上下文&quot;变强的架构 <a class="header-anchor" href="#第-6-章-transformer-—-让-读懂上下文-变强的架构" aria-label="Permalink to &quot;第 6 章　Transformer — 让&quot;读懂上下文&quot;变强的架构&quot;">​</a></h3><ul><li>之前 RNN 的困境：记不住远处</li><li>自注意力：每个词去&quot;看&quot;所有其他词、算相关性（Q/K/V 直觉讲透，不堆公式）</li><li>多头注意力、位置编码、残差 / 层归一（各自解决什么问题）</li><li>Decoder-only：为什么 GPT 类模型只往前生成</li><li>▶ 动手：最小 self-attention 演示</li></ul><h3 id="第-7-章-训练-—-把概率函数-烤-进去-1-和-2-在此合流" tabindex="-1">第 7 章　训练 — 把概率函数&quot;烤&quot;进去（#1 和 #2 在此合流） <a class="header-anchor" href="#第-7-章-训练-—-把概率函数-烤-进去-1-和-2-在此合流" aria-label="Permalink to &quot;第 7 章　训练 — 把概率函数&quot;烤&quot;进去（#1 和 #2 在此合流）&quot;">​</a></h3><ul><li>预训练 = 在海量文本上做&quot;下一个词预测&quot; = 一直在更新参数（呼应第 1 章）</li><li>损失：交叉熵（为什么这个损失对&quot;概率分布&quot;最自然）</li><li>规模律：为什么越大越强</li><li>后训练三件套：SFT（监督）→ RLHF / DPO（强化，呼应第 4 章）→ 对齐</li><li>训练要什么：数据、算力、优化器、分布式（只讲每个是干嘛的，点到为止）</li><li>▶ 动手：小语料上跑&quot;下一个词预测&quot;训练循环，看 loss 往下掉</li></ul><h3 id="第-8-章-推理-—-概率函数怎么-跑起来" tabindex="-1">第 8 章　推理 — 概率函数怎么&quot;跑起来&quot; <a class="header-anchor" href="#第-8-章-推理-—-概率函数怎么-跑起来" aria-label="Permalink to &quot;第 8 章　推理 — 概率函数怎么&quot;跑起来&quot;&quot;">​</a></h3><ul><li>推理 vs 训练：不再更新参数，只前向算概率</li><li>自回归生成：一步步采样下一个 token</li><li>采样策略：greedy / temperature / top-p / top-k（回扣第 5 章的概率分布）</li><li>KV cache（加速要点）、上下文窗口、超了怎么办</li><li>幻觉 / 重复 / &quot;一本正经胡说&quot;——全部回到概率函数解释</li><li>▶ 动手：最简自回归生成循环演示</li></ul><hr><h2 id="part-c-·-llm-工程应用-重心-最长最深-每章回扣原理" tabindex="-1">Part C · LLM 工程应用（重心，最长最深；每章回扣原理） <a class="header-anchor" href="#part-c-·-llm-工程应用-重心-最长最深-每章回扣原理" aria-label="Permalink to &quot;Part C · LLM 工程应用（重心，最长最深；每章回扣原理）&quot;">​</a></h2><h3 id="第-9-章-提示词工程-—-跟概率函数-说话" tabindex="-1">第 9 章　提示词工程 — 跟概率函数&quot;说话&quot; <a class="header-anchor" href="#第-9-章-提示词工程-—-跟概率函数-说话" aria-label="Permalink to &quot;第 9 章　提示词工程 — 跟概率函数&quot;说话&quot;&quot;">​</a></h3><ul><li>为什么 prompt 有效：你在改输入 → 改变条件概率分布</li><li>指令 / 角色 / few-shot / CoT；为什么 CoT 让模型更准（把隐式推理变成显式 token）</li><li>提示词的脆弱性与鲁棒写法</li><li>▶ 动手：同一任务对比 zero / few-shot / CoT 效果差</li></ul><h3 id="第-10-章-上下文工程-—-往概率函数的-视野-里塞什么" tabindex="-1">第 10 章　上下文工程 — 往概率函数的&quot;视野&quot;里塞什么 <a class="header-anchor" href="#第-10-章-上下文工程-—-往概率函数的-视野-里塞什么" aria-label="Permalink to &quot;第 10 章　上下文工程 — 往概率函数的&quot;视野&quot;里塞什么&quot;">​</a></h3><ul><li>上下文工程 ≠ 提示词工程：后者是&quot;说什么&quot;，前者是&quot;窗口里放什么&quot;</li><li>RAG：把外部知识检索进上下文</li><li>长上下文陷阱：lost-in-the-middle、注意力被稀释</li><li>上下文压缩、记忆系统（短期 / 长期）</li><li>▶ 动手：搭一个最简 RAG</li></ul><h3 id="第-11-章-harness-工程-—-驱动模型的-骨架" tabindex="-1">第 11 章　Harness 工程 — 驱动模型的&quot;骨架&quot; <a class="header-anchor" href="#第-11-章-harness-工程-—-驱动模型的-骨架" aria-label="Permalink to &quot;第 11 章　Harness 工程 — 驱动模型的&quot;骨架&quot;&quot;">​</a></h3><ul><li>什么是 harness：包裹 LLM 的运行时——系统提示、工具循环、记忆、重试、错误恢复</li><li><strong>核心澄清：prompt / context / harness / agent 四者的边界</strong>（这四个并列，就是为了分清它们）</li><li>工具调用机制：模型吐结构化意图 → harness 执行 → 结果回灌上下文</li><li>循环、状态管理、失败恢复</li><li>▶ 动手：写一个最简 harness（系统提示 + 工具循环 + 重试）</li></ul><h3 id="第-12-章-agent-工程-—-让模型自己朝目标走" tabindex="-1">第 12 章　Agent 工程 — 让模型自己朝目标走 <a class="header-anchor" href="#第-12-章-agent-工程-—-让模型自己朝目标走" aria-label="Permalink to &quot;第 12 章　Agent 工程 — 让模型自己朝目标走&quot;">​</a></h3><ul><li>agent = harness + 自主规划 / 循环 / 记忆 / 工具</li><li>规划：ReAct、反思、任务分解；多 agent 协作（简介）</li><li>失败模式与评估</li><li><strong>RL 驱动 agent</strong>（回扣第 4 章）：从规则驱动到学习驱动，agent 自己进化</li><li>▶ 动手：在第 11 章 harness 上加 ReAct 循环，做个能上网/算数的小 agent</li></ul><h3 id="第-13-章-收尾-—-把整条线收起来-往前看" tabindex="-1">第 13 章　收尾 — 把整条线收起来 + 往前看 <a class="header-anchor" href="#第-13-章-收尾-—-把整条线收起来-往前看" aria-label="Permalink to &quot;第 13 章　收尾 — 把整条线收起来 + 往前看&quot;">​</a></h3><ul><li>从一个神经元到一个 agent：全书脉络一张大图</li><li>第一性原理回顾：概率函数 + 参数更新，所有现象从这里出发</li><li>局限与前沿：幻觉、对齐、效率、agent 可靠性</li><li>给&quot;自己继续学&quot;的路线图</li></ul><hr><h2 id="结构小记" tabindex="-1">结构小记 <a class="header-anchor" href="#结构小记" aria-label="Permalink to &quot;结构小记&quot;">​</a></h2><ul><li>共 <strong>14 章（0–13）</strong>。两块&quot;骨头&quot;用 🔒 标出，每块都有锚点章 + 后续反复回扣。</li><li><strong>Part C（5 章）最长</strong>，呼应&quot;重工程应用&quot;；Part A / B 各 4 章，原理精炼但骨头讲透。</li><li>每章统一三段式：<strong>直觉 →（关键处）极简图示 → 可交互演示</strong>。</li></ul>',41)])])}const b=l(o,[["render",r]]);export{c as __pageData,b as default};
